import { useState, useEffect, useRef } from "react";

const PLATFORMS = [
  { name: "YouTube", color: "#FF0000", icon: "▶" },
  { name: "Instagram", color: "#E1306C", icon: "◈" },
  { name: "TikTok", color: "#69C9D0", icon: "♪" },
  { name: "LinkedIn", color: "#0077B5", icon: "in" },
  { name: "Facebook", color: "#1877F2", icon: "f" },
  { name: "X / Twitter", color: "#1DA1F2", icon: "𝕏" },
  { name: "Pinterest", color: "#E60023", icon: "P" },
];

const FEATURES = [
  {
    icon: "🗓",
    title: "Smart Calendar",
    desc: "Drag-and-drop scheduling across all platforms. See every post at a glance — filter by platform, campaign, or status.",
    tag: "Core",
    tagColor: "#00d4ff",
  },
  {
    icon: "🤖",
    title: "AI Content Studio",
    desc: "Upload once. AI auto-generates titles, captions, hashtags, thumbnail prompts, and repurposes long videos into Shorts & Reels.",
    tag: "AI",
    tagColor: "#a78bfa",
  },
  {
    icon: "⚡",
    title: "MCP Agent API",
    desc: "Expose your content pipeline as MCP tools. Let Claude, Cursor, or any AI agent schedule posts by just saying so.",
    tag: "MCP",
    tagColor: "#34d399",
  },
  {
    icon: "📦",
    title: "Bulk Scheduling",
    desc: "Upload 50 videos, schedule all 50 days automatically. CSV import or drag-and-drop folder upload.",
    tag: "Core",
    tagColor: "#00d4ff",
  },
  {
    icon: "📊",
    title: "Analytics Dashboard",
    desc: "Track views, likes, comments, watch time, CTR and follower growth across all platforms in one place.",
    tag: "Analytics",
    tagColor: "#f59e0b",
  },
  {
    icon: "👥",
    title: "Team & Approval",
    desc: "Creator → Editor → Manager approval flow. Roles: Admin, Editor, Creator, Viewer. Perfect for agencies.",
    tag: "Teams",
    tagColor: "#fb923c",
  },
];

const MCP_TOOLS = [
  "create_post", "schedule_post", "delete_post", "list_posts",
  "upload_video", "generate_caption", "generate_title", "get_analytics",
  "reschedule_post", "cancel_post", "generate_hashtags", "connect_account",
];

const STEPS = [
  { num: "01", title: "Connect Accounts", desc: "OAuth-secure connection to YouTube, Instagram, TikTok, LinkedIn, and more." },
  { num: "02", title: "Upload Your Content", desc: "Upload video/image. AI instantly generates titles, captions, and hashtags." },
  { num: "03", title: "Schedule & Publish", desc: "Pick date/time per platform. Background worker publishes exactly on time." },
  { num: "04", title: "Let AI Agents Take Over", desc: "Connect your MCP server and let AI agents manage your entire pipeline." },
];

const PRICING = [
  {
    name: "Free",
    price: "$0",
    period: "/forever",
    features: ["1 connected account", "30 scheduled posts/month", "Basic AI captions", "Calendar view", "YouTube + Instagram"],
    cta: "Start Free",
    highlight: false,
  },
  {
    name: "Creator",
    price: "$12",
    period: "/month",
    features: ["5 platforms", "Unlimited scheduling", "Full AI Studio", "Bulk import", "Analytics dashboard", "MCP API access"],
    cta: "Get Started",
    highlight: true,
  },
  {
    name: "Agency",
    price: "$49",
    period: "/month",
    features: ["Unlimited platforms", "Team workspace", "Approval workflows", "White-label reports", "Priority support", "Custom MCP tools"],
    cta: "Contact Sales",
    highlight: false,
  },
];

const STACK = [
  { layer: "Frontend", items: ["Next.js", "React", "Tailwind"], color: "#00d4ff" },
  { layer: "Backend", items: ["Node.js", "NestJS", "BullMQ"], color: "#a78bfa" },
  { layer: "Database", items: ["PostgreSQL", "Supabase", "Redis"], color: "#34d399" },
  { layer: "Storage", items: ["Cloudflare R2", "S3-compatible", "Temp for videos"], color: "#f59e0b" },
  { layer: "AI", items: ["OpenAI", "Gemini", "Whisper STT"], color: "#fb923c" },
  { layer: "Hosting", items: ["Vercel (free)", "Render (free)", "Upstash (free)"], color: "#f472b6" },
];

function Ticker() {
  const platforms = [...PLATFORMS, ...PLATFORMS];
  return (
    <div style={{ overflow: "hidden", position: "relative", padding: "12px 0" }}>
      <div style={{
        display: "flex", gap: 24, animation: "ticker 18s linear infinite",
        width: "max-content",
      }}>
        {platforms.map((p, i) => (
          <span key={i} style={{
            display: "inline-flex", alignItems: "center", gap: 8,
            background: "rgba(255,255,255,0.06)", border: "1px solid rgba(255,255,255,0.1)",
            borderRadius: 40, padding: "6px 16px", fontSize: 13, color: "#ccc",
            whiteSpace: "nowrap",
          }}>
            <span style={{ color: p.color, fontWeight: 700, fontSize: 12 }}>{p.icon}</span>
            {p.name}
          </span>
        ))}
      </div>
      <style>{`@keyframes ticker { 0%{transform:translateX(0)} 100%{transform:translateX(-50%)} }`}</style>
    </div>
  );
}

function McpDemo() {
  const [active, setActive] = useState(null);
  const [typed, setTyped] = useState("");
  const [response, setResponse] = useState("");
  const prompts = [
    { cmd: 'schedule_post("video.mp4", "YouTube", "2025-06-10T20:00")', res: '✓ Scheduled: "video.mp4" → YouTube on June 10 at 8:00 PM' },
    { cmd: 'generate_caption("fitness motivation", "instagram")', res: '✓ Caption: "Every rep counts. Every set matters. Your future self is watching. 💪 #fitness #motivation #grind"' },
    { cmd: 'get_analytics("youtube", "last_7_days")', res: '✓ Views: 14,230 | Likes: 892 | Watch Time: 48.2h | Subs: +127' },
  ];

  const runPrompt = (i) => {
    setActive(i);
    setTyped("");
    setResponse("");
    const cmd = prompts[i].cmd;
    let j = 0;
    const t1 = setInterval(() => {
      setTyped(cmd.slice(0, ++j));
      if (j >= cmd.length) { clearInterval(t1); setTimeout(() => setResponse(prompts[i].res), 400); }
    }, 28);
  };

  return (
    <div style={{ background: "#0d0d0d", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 16, overflow: "hidden" }}>
      <div style={{ padding: "12px 16px", borderBottom: "1px solid rgba(255,255,255,0.08)", display: "flex", gap: 6 }}>
        {["#ff5f57","#febc2e","#28c840"].map((c,i) => <span key={i} style={{width:10,height:10,borderRadius:"50%",background:c,display:"inline-block"}}/>)}
        <span style={{ fontSize: 12, color: "#555", marginLeft: 8 }}>contentOS MCP Server — AI Agent Terminal</span>
      </div>
      <div style={{ padding: 20, minHeight: 160 }}>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 16 }}>
          {prompts.map((p, i) => (
            <button key={i} onClick={() => runPrompt(i)} style={{
              background: active === i ? "rgba(0,212,255,0.15)" : "rgba(255,255,255,0.05)",
              border: `1px solid ${active === i ? "rgba(0,212,255,0.4)" : "rgba(255,255,255,0.08)"}`,
              borderRadius: 6, padding: "4px 12px", fontSize: 11, color: active === i ? "#00d4ff" : "#888",
              cursor: "pointer", transition: "all 0.2s",
            }}>
              {["schedule", "caption", "analytics"][i]}
            </button>
          ))}
        </div>
        {typed && (
          <div style={{ fontFamily: "'Fira Code', monospace", fontSize: 12 }}>
            <span style={{ color: "#34d399" }}>agent@contentOS</span>
            <span style={{ color: "#888" }}> ~ % </span>
            <span style={{ color: "#e2e8f0" }}>{typed}</span>
            <span style={{ animation: "blink 1s infinite", color: "#00d4ff" }}>|</span>
          </div>
        )}
        {response && (
          <div style={{ marginTop: 12, fontSize: 12, color: "#34d399", fontFamily: "'Fira Code', monospace", lineHeight: 1.6 }}>
            {response}
          </div>
        )}
        {!typed && !response && (
          <div style={{ color: "#444", fontSize: 12, fontFamily: "'Fira Code', monospace" }}>
            → Click a tool above to see MCP in action
          </div>
        )}
      </div>
      <style>{`@keyframes blink{0%,100%{opacity:1}50%{opacity:0}}`}</style>
    </div>
  );
}

function FeatureCard({ feat }) {
  const [hov, setHov] = useState(false);
  return (
    <div
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        background: hov ? "rgba(255,255,255,0.05)" : "rgba(255,255,255,0.03)",
        border: `1px solid ${hov ? "rgba(255,255,255,0.15)" : "rgba(255,255,255,0.07)"}`,
        borderRadius: 16, padding: 24,
        transition: "all 0.25s", cursor: "default",
        transform: hov ? "translateY(-2px)" : "none",
      }}
    >
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 14 }}>
        <span style={{ fontSize: 28 }}>{feat.icon}</span>
        <span style={{
          background: `${feat.tagColor}20`,
          border: `1px solid ${feat.tagColor}40`,
          color: feat.tagColor, borderRadius: 20, padding: "2px 10px", fontSize: 11, fontWeight: 600,
        }}>{feat.tag}</span>
      </div>
      <h3 style={{ fontSize: 17, fontWeight: 700, color: "#f1f5f9", margin: "0 0 8px" }}>{feat.title}</h3>
      <p style={{ fontSize: 13.5, color: "#94a3b8", lineHeight: 1.6, margin: 0 }}>{feat.desc}</p>
    </div>
  );
}

export default function App() {
  const [scrolled, setScrolled] = useState(false);
  const [activeFaq, setActiveFaq] = useState(null);

  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 40);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);

  const faqs = [
    { q: "Can I use this completely for free?", a: "Yes. The free tier supports 1 connected account and 30 scheduled posts per month. YouTube and Instagram APIs are free to use within their quota limits. You can host the app on Vercel + Supabase + Cloudflare R2 for $0." },
    { q: "Do I need my own server to store videos?", a: "No. For YouTube, your app streams the video directly to YouTube's servers. You only need temporary disk space during upload. Your database only stores metadata (title, caption, schedule time, video ID)." },
    { q: "Can I run this locally?", a: "Yes. You can run the backend on localhost (Node.js + PostgreSQL) and still use YouTube/Instagram APIs. Your machine just needs internet access to reach Google/Meta servers at scheduled time." },
    { q: "What is MCP and why does it matter?", a: "MCP (Model Context Protocol) lets AI agents like Claude or Cursor control your content pipeline via tools. Instead of clicking through a UI, your AI can call schedule_post() or generate_caption() automatically." },
    { q: "Does Instagram require a Business account?", a: "Yes. Instagram Graph API (for publishing) only works with Business or Creator accounts linked to a Facebook Page. Personal accounts are not supported by the official API." },
  ];

  return (
    <div style={{ fontFamily: "'DM Sans', 'Segoe UI', sans-serif", background: "#080808", color: "#e2e8f0", minHeight: "100vh" }}>
      <link href="https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;700;900&family=Fira+Code&display=swap" rel="stylesheet" />

      {/* NAV */}
      <nav style={{
        position: "sticky", top: 0, zIndex: 100,
        background: scrolled ? "rgba(8,8,8,0.92)" : "transparent",
        backdropFilter: scrolled ? "blur(12px)" : "none",
        borderBottom: scrolled ? "1px solid rgba(255,255,255,0.07)" : "none",
        transition: "all 0.3s", padding: "0 40px",
        display: "flex", alignItems: "center", justifyContent: "space-between", height: 60,
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <div style={{ width: 28, height: 28, background: "linear-gradient(135deg, #00d4ff, #a78bfa)", borderRadius: 8 }} />
          <span style={{ fontWeight: 900, fontSize: 18, letterSpacing: -0.5, color: "#fff" }}>ContentOS</span>
        </div>
        <div style={{ display: "flex", gap: 28, fontSize: 14, color: "#94a3b8" }}>
          {["Features", "How it works", "Pricing", "Stack"].map(l => (
            <a key={l} href={`#${l.toLowerCase().replace(" ", "-")}`} style={{ color: "inherit", textDecoration: "none", transition: "color 0.2s" }}
              onMouseEnter={e => e.target.style.color = "#fff"}
              onMouseLeave={e => e.target.style.color = "#94a3b8"}>{l}</a>
          ))}
        </div>
        <button style={{
          background: "linear-gradient(135deg, #00d4ff, #0099bb)", border: "none", borderRadius: 8,
          padding: "8px 20px", fontSize: 14, fontWeight: 600, color: "#000", cursor: "pointer",
        }}>Get Started Free</button>
      </nav>

      {/* HERO */}
      <section style={{ textAlign: "center", padding: "100px 40px 60px", position: "relative", overflow: "hidden" }}>
        <div style={{
          position: "absolute", top: -200, left: "50%", transform: "translateX(-50%)",
          width: 600, height: 600, borderRadius: "50%",
          background: "radial-gradient(circle, rgba(0,212,255,0.07) 0%, transparent 70%)",
          pointerEvents: "none",
        }} />
        <div style={{
          display: "inline-flex", alignItems: "center", gap: 8,
          background: "rgba(0,212,255,0.08)", border: "1px solid rgba(0,212,255,0.2)",
          borderRadius: 40, padding: "6px 16px", fontSize: 12, color: "#00d4ff",
          marginBottom: 32, fontWeight: 600,
        }}>
          ⚡ NOW WITH MCP AGENT INTEGRATION
        </div>
        <h1 style={{
          fontSize: "clamp(40px, 6vw, 76px)", fontWeight: 900, lineHeight: 1.08,
          letterSpacing: -2, margin: "0 auto 24px", maxWidth: 800,
          background: "linear-gradient(180deg, #ffffff 0%, #94a3b8 100%)",
          WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
        }}>
          The AI-Native<br />Content Operating System
        </h1>
        <p style={{ fontSize: 18, color: "#94a3b8", maxWidth: 560, margin: "0 auto 40px", lineHeight: 1.7 }}>
          Upload once. Generate everything. Schedule everywhere.
          Let AI agents manage your entire content pipeline through MCP.
        </p>
        <div style={{ display: "flex", gap: 12, justifyContent: "center", flexWrap: "wrap" }}>
          <button style={{
            background: "linear-gradient(135deg, #00d4ff, #0099bb)", border: "none", borderRadius: 10,
            padding: "14px 32px", fontSize: 15, fontWeight: 700, color: "#000", cursor: "pointer",
          }}>Start Building Free →</button>
          <button style={{
            background: "transparent", border: "1px solid rgba(255,255,255,0.15)", borderRadius: 10,
            padding: "14px 32px", fontSize: 15, fontWeight: 500, color: "#fff", cursor: "pointer",
          }}>View on GitHub</button>
        </div>

        <div style={{ marginTop: 60, maxWidth: 700, margin: "60px auto 0" }}>
          <p style={{ fontSize: 11, color: "#555", textTransform: "uppercase", letterSpacing: 2, marginBottom: 16 }}>Publishes to</p>
          <Ticker />
        </div>
      </section>

      {/* DASHBOARD MOCKUP */}
      <section style={{ padding: "20px 40px 80px", maxWidth: 1000, margin: "0 auto" }}>
        <div style={{
          background: "#0f0f0f", border: "1px solid rgba(255,255,255,0.1)",
          borderRadius: 20, overflow: "hidden",
        }}>
          <div style={{ padding: "12px 20px", borderBottom: "1px solid rgba(255,255,255,0.07)", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
            <div style={{ display: "flex", gap: 6 }}>
              {["#ff5f57","#febc2e","#28c840"].map((c,i) => <span key={i} style={{width:11,height:11,borderRadius:"50%",background:c,display:"inline-block"}}/>)}
            </div>
            <span style={{ fontSize: 12, color: "#555" }}>contentOS — Dashboard</span>
            <div style={{ display: "flex", gap: 8 }}>
              {["Calendar","Analytics","Studio","MCP"].map(t => (
                <span key={t} style={{ fontSize: 11, color: t === "Calendar" ? "#00d4ff" : "#555", padding: "3px 10px", background: t === "Calendar" ? "rgba(0,212,255,0.1)" : "transparent", borderRadius: 4 }}>{t}</span>
              ))}
            </div>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "200px 1fr", minHeight: 380 }}>
            <div style={{ borderRight: "1px solid rgba(255,255,255,0.07)", padding: 16 }}>
              <div style={{ fontSize: 10, color: "#555", textTransform: "uppercase", letterSpacing: 1.5, marginBottom: 12 }}>Platforms</div>
              {PLATFORMS.slice(0, 5).map(p => (
                <div key={p.name} style={{ display: "flex", alignItems: "center", gap: 8, padding: "7px 8px", borderRadius: 6, marginBottom: 2, background: p.name === "YouTube" ? "rgba(255,255,255,0.05)" : "transparent" }}>
                  <span style={{ color: p.color, fontSize: 12, fontWeight: 700 }}>{p.icon}</span>
                  <span style={{ fontSize: 13, color: p.name === "YouTube" ? "#fff" : "#666" }}>{p.name}</span>
                </div>
              ))}
              <div style={{ marginTop: 20, fontSize: 10, color: "#555", textTransform: "uppercase", letterSpacing: 1.5, marginBottom: 12 }}>Upcoming</div>
              {[
                { title: "Morning Routine Vlog", time: "Today 8 AM", platform: "#FF0000" },
                { title: "Product Review Reel", time: "Today 12 PM", platform: "#E1306C" },
                { title: "Tech Tips Short", time: "Tomorrow 6 PM", platform: "#69C9D0" },
              ].map((p, i) => (
                <div key={i} style={{ padding: "8px", borderRadius: 6, marginBottom: 6, background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.05)" }}>
                  <div style={{ fontSize: 11, color: "#ddd", marginBottom: 2 }}>{p.title}</div>
                  <div style={{ fontSize: 10, color: "#555" }}>
                    <span style={{ color: p.platform }}>● </span>{p.time}
                  </div>
                </div>
              ))}
            </div>
            <div style={{ padding: 20 }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
                <div>
                  <span style={{ fontSize: 15, fontWeight: 700, color: "#fff" }}>June 2025</span>
                  <span style={{ fontSize: 13, color: "#555", marginLeft: 12 }}>12 posts scheduled</span>
                </div>
                <button style={{ background: "rgba(0,212,255,0.1)", border: "1px solid rgba(0,212,255,0.2)", borderRadius: 6, padding: "5px 14px", fontSize: 12, color: "#00d4ff", cursor: "pointer" }}>+ New Post</button>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 4, marginBottom: 8 }}>
                {["Mon","Tue","Wed","Thu","Fri","Sat","Sun"].map(d => (
                  <div key={d} style={{ textAlign: "center", fontSize: 10, color: "#555", padding: "4px 0" }}>{d}</div>
                ))}
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 4 }}>
                {Array.from({ length: 35 }, (_, i) => {
                  const day = i - 2;
                  const hasPosts = [1,3,5,7,8,11,14,16,18,20,22,25].includes(day);
                  const isToday = day === 10;
                  const platforms = hasPosts ? [["#FF0000","#E1306C","#69C9D0"][day % 3]] : [];
                  return (
                    <div key={i} style={{
                      minHeight: 48, borderRadius: 6, padding: 4,
                      background: isToday ? "rgba(0,212,255,0.1)" : hasPosts ? "rgba(255,255,255,0.03)" : "transparent",
                      border: isToday ? "1px solid rgba(0,212,255,0.3)" : "1px solid transparent",
                    }}>
                      {day > 0 && day <= 30 && (
                        <>
                          <div style={{ fontSize: 10, color: isToday ? "#00d4ff" : "#666", fontWeight: isToday ? 700 : 400 }}>{day}</div>
                          {hasPosts && (
                            <div style={{ display: "flex", gap: 2, marginTop: 2, flexWrap: "wrap" }}>
                              {platforms.map((c, pi) => <span key={pi} style={{ width: 6, height: 6, borderRadius: "50%", background: c, display: "inline-block" }} />)}
                            </div>
                          )}
                        </>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* FEATURES */}
      <section id="features" style={{ padding: "80px 40px", maxWidth: 1100, margin: "0 auto" }}>
        <div style={{ textAlign: "center", marginBottom: 60 }}>
          <p style={{ fontSize: 12, color: "#00d4ff", textTransform: "uppercase", letterSpacing: 3, marginBottom: 12 }}>Everything You Need</p>
          <h2 style={{ fontSize: 42, fontWeight: 900, letterSpacing: -1, color: "#fff", margin: 0 }}>Built for creators.<br />Designed for agents.</h2>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))", gap: 16 }}>
          {FEATURES.map((f, i) => <FeatureCard key={i} feat={f} />)}
        </div>
      </section>

      {/* HOW IT WORKS */}
      <section id="how-it-works" style={{ padding: "80px 40px", background: "rgba(255,255,255,0.02)", borderTop: "1px solid rgba(255,255,255,0.06)", borderBottom: "1px solid rgba(255,255,255,0.06)" }}>
        <div style={{ maxWidth: 1000, margin: "0 auto" }}>
          <div style={{ textAlign: "center", marginBottom: 60 }}>
            <p style={{ fontSize: 12, color: "#a78bfa", textTransform: "uppercase", letterSpacing: 3, marginBottom: 12 }}>How It Works</p>
            <h2 style={{ fontSize: 42, fontWeight: 900, letterSpacing: -1, color: "#fff", margin: 0 }}>From upload to published<br />in 4 steps</h2>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 24 }}>
            {STEPS.map((s, i) => (
              <div key={i} style={{ position: "relative" }}>
                <div style={{ fontSize: 48, fontWeight: 900, color: "rgba(255,255,255,0.06)", lineHeight: 1, marginBottom: 12, letterSpacing: -2 }}>{s.num}</div>
                <h3 style={{ fontSize: 17, fontWeight: 700, color: "#fff", margin: "0 0 10px" }}>{s.title}</h3>
                <p style={{ fontSize: 13.5, color: "#94a3b8", lineHeight: 1.6, margin: 0 }}>{s.desc}</p>
                {i < 3 && <div style={{ position: "absolute", top: 24, right: -12, fontSize: 20, color: "#333" }}>→</div>}
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* MCP SECTION */}
      <section style={{ padding: "80px 40px", maxWidth: 1000, margin: "0 auto" }}>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 60, alignItems: "center" }}>
          <div>
            <div style={{
              display: "inline-flex", alignItems: "center", gap: 8,
              background: "rgba(52,211,153,0.08)", border: "1px solid rgba(52,211,153,0.2)",
              borderRadius: 40, padding: "6px 16px", fontSize: 12, color: "#34d399",
              marginBottom: 24, fontWeight: 600,
            }}>⚡ MCP INTEGRATION</div>
            <h2 style={{ fontSize: 38, fontWeight: 900, letterSpacing: -1, color: "#fff", margin: "0 0 20px", lineHeight: 1.15 }}>
              Let AI agents<br />run your content
            </h2>
            <p style={{ fontSize: 15, color: "#94a3b8", lineHeight: 1.7, marginBottom: 24 }}>
              ContentOS exposes a full MCP server. Connect it to Claude, Cursor, or any AI agent and let them schedule posts, generate captions, and pull analytics — all through natural language.
            </p>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
              {MCP_TOOLS.map(t => (
