              {["schedule", "caption", "analytics"][i]}
            </button>
          ))}
        </div>
        {typed && (
          <div style={{ fontFamily: "'Fira Code', monospace", fontSize: 12 }}>
            <span style={{ color: "#34d399" }}>agent@contentOS</span>
            <span style={{ color: "#888" }}> ~ % </span>
            <span style={{ color: "#e2e8f0" }}>{typed}</span>
