// src/queue.js
const { Queue, Worker, QueueScheduler, QueueEvents } = require("bullmq");
const IORedis = require("ioredis");
const logger = require("./logger");

let redisConnection = null;

// ─── Redis Connection ──────────────────────────────────────────────────
async function connectRedis() {
  redisConnection = new IORedis(process.env.REDIS_URL || "redis://localhost:6379", {
    maxRetriesPerRequest: null,
    enableReadyCheck: false,
    lazyConnect: true,
  });

  redisConnection.on("connect", () => logger.info("Redis connected"));
  redisConnection.on("error", (err) => logger.error("Redis error:", err.message));

  await redisConnection.connect();
  return redisConnection;
}

function getRedis() {
  if (!redisConnection) throw new Error("Redis not connected. Call connectRedis() first.");
  return redisConnection;
}

// ─── Queue Names ──────────────────────────────────────────────────────
const QUEUE_NAMES = {
  PUBLISH: "publish-post",
  AI_GENERATE: "ai-generate",
};

// ─── Get or create a queue ────────────────────────────────────────────
const queues = {};

function getQueue(name) {
  if (!queues[name]) {
    queues[name] = new Queue(name, {
      connection: getRedis(),
      defaultJobOptions: {
        attempts: 3,
        backoff: { type: "exponential", delay: 5000 },
        removeOnComplete: { count: 200 },
        removeOnFail: { count: 500 },
      },
    });
  }
  return queues[name];
}

// ─── Schedule a publish job ────────────────────────────────────────────
/**
 * Schedule a post to be published at a specific time.
 * @param {string} postId  - ScheduledPost.id
 * @param {Date}   runAt   - When to publish
 * @returns {string}       - BullMQ job ID
 */
async function schedulePublishJob(postId, runAt) {
  const queue = getQueue(QUEUE_NAMES.PUBLISH);
  const delay = Math.max(0, new Date(runAt).getTime() - Date.now());

  const job = await queue.add(
    "publish",
    { postId },
    {
      delay,
      jobId: `post-${postId}`,  // idempotent: same post won't be queued twice
    }
  );

  logger.info(`Publish job scheduled: post=${postId}, delay=${Math.round(delay / 1000)}s, jobId=${job.id}`);
  return job.id;
}

// ─── Cancel a scheduled job ───────────────────────────────────────────
async function cancelPublishJob(jobId) {
  const queue = getQueue(QUEUE_NAMES.PUBLISH);
  const job = await queue.getJob(jobId);
  if (job) {
    await job.remove();
    logger.info(`Publish job cancelled: jobId=${jobId}`);
  }
}

// ─── Schedule AI generation job ───────────────────────────────────────
async function scheduleAiGenerateJob(mediaFileId, userId) {
  const queue = getQueue(QUEUE_NAMES.AI_GENERATE);
  const job = await queue.add("generate", { mediaFileId, userId });
  return job.id;
}

module.exports = {
  connectRedis,
  getRedis,
  getQueue,
  schedulePublishJob,
  cancelPublishJob,
  scheduleAiGenerateJob,
  QUEUE_NAMES,
};

