        userId: req.user.id,
        title: data.title,
        caption: data.caption,
        description: data.description,
        hashtags: data.hashtags,
        platforms: data.platforms,
        scheduledAt,
        privacyStatus: data.privacyStatus,
        mediaFileId: data.mediaFileId || null,
        status: "SCHEDULED",
      },
