// src/services/ai.js
const OpenAI = require("openai");
const fs = require("fs");
const path = require("path");
const logger = require("../logger");

let openai = null;

function getClient() {
  if (!openai) {
    if (!process.env.OPENAI_API_KEY) throw new Error("OPENAI_API_KEY not set");
    openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
  }
  return openai;
}

// ─── Generate title, caption, and hashtags from a text prompt ─────────
/**
 * @param {{ topic: string, tone?: string, platforms?: string[] }}
 * @returns {{ title: string, caption: string, hashtags: string[], description: string }}
 */
async function generateContent({ topic, tone = "engaging", platforms = ["YOUTUBE", "INSTAGRAM"] }) {
  const client = getClient();

  const prompt = `You are a professional social media content strategist.
Generate content for a post about: "${topic}"
Tone: ${tone}
Platforms: ${platforms.join(", ")}

Return ONLY valid JSON with these fields:
{
  "title": "YouTube-optimized title (max 100 chars, click-worthy)",
  "caption": "Instagram caption (2-3 sentences, conversational, max 200 chars)",
  "description": "YouTube long-form description (150-300 words, includes call-to-action)",
  "hashtags": ["array", "of", "10", "relevant", "hashtags", "without", "the", "#"],
  "suggestedTime": "Best time to post as HH:MM in 24h format",
  "contentIdeas": ["3 follow-up content idea titles"]
}`;

  const response = await client.chat.completions.create({
    model: process.env.OPENAI_MODEL || "gpt-4o-mini",
    messages: [{ role: "user", content: prompt }],
    response_format: { type: "json_object" },
    temperature: 0.8,
  });

  const result = JSON.parse(response.choices[0].message.content);
  logger.debug(`AI generated content for topic: ${topic}`);
  return result;
}

// ─── Generate multiple caption variants ──────────────────────────────
async function generateCaptionVariants({ topic, platform, count = 3 }) {
  const client = getClient();

  const response = await client.chat.completions.create({
    model: process.env.OPENAI_MODEL || "gpt-4o-mini",
    messages: [{
      role: "user",
      content: `Generate ${count} different ${platform} captions for: "${topic}". 
Each should have a different style (professional, casual, motivational).
Return ONLY valid JSON: { "variants": [{"style": "...", "caption": "...", "hashtags": ["..."]}] }`,
    }],
    response_format: { type: "json_object" },
    temperature: 0.9,
  });

  return JSON.parse(response.choices[0].message.content);
}

// ─── Generate content from an uploaded media file ────────────────────
async function generateContentFromMedia(mediaFile) {
  const client = getClient();
  const isVideo = mediaFile.mimeType?.startsWith("video/");
  const isImage = mediaFile.mimeType?.startsWith("image/");

  // For images: use vision API
  if (isImage) {
    const filePath = path.isAbsolute(mediaFile.storageUrl)
      ? mediaFile.storageUrl
      : path.join(process.cwd(), "uploads", path.basename(mediaFile.storageUrl));

    if (fs.existsSync(filePath)) {
      const imageData = fs.readFileSync(filePath, "base64");
      const mimeType = mediaFile.mimeType;

      const response = await client.chat.completions.create({
        model: "gpt-4o",  // Vision model needed
        messages: [{
          role: "user",
          content: [
            {
              type: "image_url",
              image_url: { url: `data:${mimeType};base64,${imageData}` },
            },
            {
              type: "text",
              text: `Analyze this image and generate social media content.
Return ONLY valid JSON:
{
  "title": "YouTube title if this were a video thumbnail",
  "caption": "Instagram caption (engaging, 1-2 sentences)",
  "description": "Longer YouTube description",
  "hashtags": ["10", "relevant", "hashtags"],
  "imageDescription": "What's in this image"
}`,
            },
          ],
        }],
        response_format: { type: "json_object" },
      });

      return JSON.parse(response.choices[0].message.content);
    }
  }

  // For videos (or images we can't read): generate from filename/metadata
  const filename = mediaFile.originalName || "untitled";
  return await generateContent({
    topic: filename.replace(/\.[^.]+$/, "").replace(/[-_]/g, " "),
    platforms: ["YOUTUBE", "INSTAGRAM"],
  });
}

// ─── Rewrite caption in different style ──────────────────────────────
async function rewriteCaption({ caption, style = "shorter" }) {
  const client = getClient();
  const STYLES = {
    shorter: "Rewrite this caption to be shorter (max 100 chars) while keeping the message",
    longer: "Expand this caption with more detail and storytelling (max 400 chars)",
    formal: "Rewrite this caption in a professional, formal tone",
    casual: "Rewrite this caption in a casual, friendly, Gen-Z friendly tone",
    question: "Rewrite this caption to end with an engaging question to boost comments",
  };

  const instruction = STYLES[style] || `Rewrite this caption to be ${style}`;

  const response = await client.chat.completions.create({
    model: process.env.OPENAI_MODEL || "gpt-4o-mini",
    messages: [{ role: "user", content: `${instruction}:\n\n"${caption}"\n\nReturn ONLY the rewritten caption, no explanation.` }],
  });

  return { caption: response.choices[0].message.content.trim() };
}

// ─── Generate hashtag set ─────────────────────────────────────────────
async function generateHashtags({ topic, platform = "INSTAGRAM", count = 15 }) {
  const client = getClient();

  const response = await client.chat.completions.create({
    model: process.env.OPENAI_MODEL || "gpt-4o-mini",
    messages: [{
      role: "user",
      content: `Generate ${count} optimized ${platform} hashtags for: "${topic}".
Mix of: high-volume (broad), medium (niche), low-volume (specific).
Return ONLY valid JSON: { "hashtags": ["without", "hash", "symbol"] }`,
    }],
    response_format: { type: "json_object" },
  });

  return JSON.parse(response.choices[0].message.content);
}

// ─── Suggest best posting times ───────────────────────────────────────
function suggestPostingTimes(platform, timezone = "UTC") {
  // Rule-based defaults (in production: use analytics to personalize)
  const defaults = {
    YOUTUBE: ["08:00", "14:00", "18:00", "20:00"],
    INSTAGRAM: ["07:00", "11:00", "13:00", "17:00", "19:00"],
    TIKTOK: ["07:00", "12:00", "19:00", "21:00"],
    LINKEDIN: ["08:00", "10:00", "12:00", "17:00"],
    FACEBOOK: ["09:00", "13:00", "15:00", "20:00"],
    TWITTER: ["09:00", "12:00", "15:00", "18:00"],
  };

  return {
    platform,
    timezone,
    times: defaults[platform] || ["09:00", "12:00", "18:00"],
    note: "These are general best practices. Connect analytics for personalized suggestions.",
  };
}

module.exports = {
  generateContent,
  generateCaptionVariants,
  generateContentFromMedia,
  rewriteCaption,
  generateHashtags,
  suggestPostingTimes,
};

