import { Outlet, NavLink, useNavigate } from "react-router-dom";
import { useAuth } from "../context";

const NAV = [
  { to: "/dashboard",   icon: "⊞",  label: "Dashboard" },
  { to: "/create",      icon: "＋",  label: "Create Post" },
  { to: "/calendar",    icon: "📅",  label: "Calendar" },
  { to: "/posts",       icon: "☰",   label: "All Posts" },
  { to: "/media",       icon: "🗂",  label: "Media Library" },
  { to: "/ai-studio",   icon: "✦",   label: "AI Studio" },
  { to: "/platforms",   icon: "⚡",  label: "Connect Accounts" },
  { to: "/analytics",   icon: "📊",  label: "Analytics" },
  { to: "/settings",    icon: "⚙",   label: "Settings" },
];

const PLATFORM_COLORS = {
  YOUTUBE: "#FF0000", INSTAGRAM: "#E1306C", TWITTER: "#1DA1F2",
  LINKEDIN: "#0077B5", TIKTOK: "#69C9D0", FACEBOOK: "#1877F2",
  PINTEREST: "#E60023",
};

export default function Layout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => { logout(); navigate("/login"); };

  return (
    <div className="app-layout">
      {/* ── Sidebar ── */}
      <aside style={{
        width: "var(--sidebar)", position: "fixed", top: 0, left: 0, height: "100vh",
        background: "var(--bg2)", borderRight: "1px solid var(--border)",
        display: "flex", flexDirection: "column", zIndex: 50,
      }}>
        {/* Logo */}
        <div style={{ padding: "20px 18px 16px", borderBottom: "1px solid var(--border)" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <div style={{ width:28, height:28, background:"linear-gradient(135deg,#00d4ff,#a78bfa)", borderRadius:8 }} />
            <span style={{ fontWeight:800, fontSize:16, letterSpacing:-0.5 }}>ContentOS</span>
          </div>
        </div>

        {/* Nav */}
        <nav style={{ flex:1, padding:"12px 10px", overflowY:"auto" }}>
          {NAV.map(({ to, icon, label }) => (
            <NavLink key={to} to={to} style={({ isActive }) => ({
              display: "flex", alignItems: "center", gap: 10,
              padding: "9px 10px", borderRadius: 8, marginBottom: 2,
              fontSize: 13.5, fontWeight: isActive ? 600 : 400,
              color: isActive ? "#fff" : "var(--muted2)",
              background: isActive ? "rgba(0,212,255,0.1)" : "transparent",
              transition: "all 0.15s",
              textDecoration: "none",
            })}>
              <span style={{ fontSize:15, width:18, textAlign:"center" }}>{icon}</span>
              {label}
            </NavLink>
          ))}
        </nav>

        {/* User */}
        <div style={{ padding:"14px 14px", borderTop:"1px solid var(--border)" }}>
          <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:10 }}>
            <div style={{
              width:30, height:30, borderRadius:"50%",
              background:"linear-gradient(135deg,#00d4ff,#a78bfa)",
              display:"flex", alignItems:"center", justifyContent:"center",
              fontSize:12, fontWeight:700, color:"#000", flexShrink:0,
            }}>
              {(user?.name || user?.email || "U")[0].toUpperCase()}
            </div>
            <div style={{ overflow:"hidden" }}>
              <div style={{ fontSize:13, fontWeight:600, whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>
                {user?.name || "User"}
              </div>
              <div style={{ fontSize:11, color:"var(--muted)", whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>
                {user?.email}
              </div>
            </div>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={handleLogout} style={{ width:"100%", justifyContent:"center" }}>
            Sign out
          </button>
        </div>
      </aside>

      {/* ── Main ── */}
      <main className="main-content">
        <Outlet />
      </main>
    </div>
  );
}

