                          · expires {new Date(connected.tokenExpiresAt).toLocaleDateString()}
                        </span>
                      )}
                    </div>
                  )}
                </div>
                {/* Action */}
                {connected ? (
                  <button
                    className="btn btn-danger btn-sm"
                    onClick={() => disconnect(connected)}
                    disabled={disconnecting === connected.id}
                  >
                    {disconnecting === connected.id ? <span className="spinner" /> : "Disconnect"}
                  </button>
                ) : (
                  <button
                    className="btn btn-primary btn-sm"
                    onClick={() => connect(p.key)}
                    disabled={!p.available || connecting === p.key}
                    style={{ background: p.available ? undefined : "var(--bg3)", color: p.available ? undefined : "var(--muted)" }}
                  >
                    {connecting === p.key ? <span className="spinner" /> : "Connect"}
                  </button>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Instagram note */}
      <div className="card" style={{ marginTop:20, borderColor:"rgba(251,191,36,0.2)", background:"rgba(251,191,36,0.05)" }}>
        <div style={{ fontSize:13, color:"var(--yellow)", fontWeight:600, marginBottom:6 }}>📌 Instagram Requirements</div>
        <p style={{ fontSize:12, color:"var(--muted2)", lineHeight:1.6 }}>
          Instagram's API only supports <strong>Business or Creator accounts</strong> connected to a Facebook Page.
          Personal accounts cannot be used for scheduling. Make sure to switch your account type in the Instagram app first.
        </p>
      </div>
    </div>
  );
}
