import { useState, useEffect, useRef } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { mediaApi, postApi, platformApi, scheduleApi } from "../api";
import { useToast } from "../context";

const PLATFORMS = ["YOUTUBE","INSTAGRAM","TWITTER","LINKEDIN","TIKTOK","FACEBOOK","PINTEREST"];
const PLATFORM_META = {
  YOUTUBE:   { icon:"▶", color:"#FF0000" }, INSTAGRAM: { icon:"◈", color:"#E1306C" },
  TWITTER:   { icon:"𝕏", color:"#1DA1F2" }, LINKEDIN:  { icon:"in", color:"#0077B5" },
  TIKTOK:    { icon:"♪", color:"#69C9D0" }, FACEBOOK:  { icon:"f", color:"#1877F2" },
  PINTEREST: { icon:"P", color:"#E60023" },
};

// Default scheduledAt = tomorrow 9am local
function defaultScheduleTime() {
  const d = new Date();
  d.setDate(d.getDate() + 1);
  d.setHours(9, 0, 0, 0);
  return d.toISOString().slice(0, 16);
}

export default function CreatePost() {
  const [step, setStep] = useState(1); // 1=upload 2=details 3=schedule
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [uploading, setUploading] = useState(false);
  const [mediaFile, setMediaFile] = useState(null);
  const [connectedPlatforms, setConnectedPlatforms] = useState([]);
  const [aiLoading, setAiLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const fileRef = useRef();
  const toast = useToast();
  const navigate = useNavigate();

  const [form, setForm] = useState({
    title: "", caption: "", description: "", hashtags: "",
    platforms: [], scheduledAt: defaultScheduleTime(), privacyStatus: "PUBLIC",
  });

  useEffect(() => {
    platformApi.list().then(r => {
      setConnectedPlatforms(r.data.accounts.map(a => a.platform));
    }).catch(() => {});
  }, []);

  // Handle file pick
  const onFile = (f) => {
    if (!f) return;
    setFile(f);
    const url = URL.createObjectURL(f);
    setPreview(url);
    setStep(2);
  };

  // Upload file to backend
  const uploadFile = async () => {
    if (!file) { setStep(2); return; }
    setUploading(true);
    try {
      const res = await mediaApi.upload(file, (e) => {
        setUploadProgress(Math.round((e.loaded / e.total) * 100));
      });
      setMediaFile(res.data.mediaFile);
      toast.success("File uploaded");
    } catch (err) {
      toast.error(err);
    } finally {
      setUploading(false);
    }
  };

  // AI generate content
  const generateAi = async () => {
    if (!form.title && !file?.name) return;
    const topic = form.title || file?.name?.replace(/\.[^.]+$/, "").replace(/[-_]/g, " ") || "content";
    setAiLoading(true);
    try {
      const res = await scheduleApi.aiGenerate(topic, "engaging", form.platforms.length ? form.platforms : ["YOUTUBE","INSTAGRAM"]);
      const g = res.data.generated;
      setForm(f => ({
        ...f,
        title: g.title || f.title,
        caption: g.caption || f.caption,
        description: g.description || f.description,
        hashtags: (g.hashtags || []).join(", "),
      }));
      toast.success("AI content generated!");
    } catch { toast.error("AI generation failed. Is OPENAI_API_KEY set?"); }
    finally { setAiLoading(false); }
  };

  // Toggle platform
  const togglePlatform = (p) => {
    setForm(f => ({
      ...f,
      platforms: f.platforms.includes(p) ? f.platforms.filter(x => x !== p) : [...f.platforms, p],
    }));
  };

  // Submit
  const submit = async () => {
    if (!form.title) { toast.error("Title is required"); return; }
    if (form.platforms.length === 0) { toast.error("Select at least one platform"); return; }
    if (!form.scheduledAt) { toast.error("Schedule time is required"); return; }

    // Upload file first if not uploaded
    if (file && !mediaFile) {
      await uploadFile();
      return; // will be called again after upload
    }

    setSubmitting(true);
    try {
      const hashtags = form.hashtags.split(",").map(h => h.trim().replace(/^#/, "")).filter(Boolean);
      await postApi.create({
        title: form.title,
        caption: form.caption,
        description: form.description,
        hashtags,
        platforms: form.platforms,
        scheduledAt: new Date(form.scheduledAt).toISOString(),
        mediaFileId: mediaFile?.id || undefined,
        privacyStatus: form.privacyStatus,
      });
      toast.success("Post scheduled successfully!");
      navigate("/calendar");
    } catch (err) { toast.error(err); }
    finally { setSubmitting(false); }
  };

  const set = (k) => (e) => setForm(f => ({ ...f, [k]: e.target.value }));

  return (
    <div className="page">
      <div className="page-header">
        <h1 className="page-title">Create & Schedule Post</h1>
        <p className="page-subtitle">Upload content, fill in details, then schedule</p>
      </div>

      <div style={{ display:"grid", gridTemplateColumns:"1fr 340px", gap:24, alignItems:"start" }}>
        {/* LEFT: Main form */}
        <div style={{ display:"flex", flexDirection:"column", gap:20 }}>

          {/* STEP 1: Upload */}
          <div className="card">
            <div style={{ fontSize:14, fontWeight:700, marginBottom:14, display:"flex", justifyContent:"space-between" }}>
              <span>📁 Media File</span>
              {mediaFile && <span style={{ color:"var(--green)", fontSize:12 }}>✓ Uploaded</span>}
            </div>

            {!file ? (
              <div
                onClick={() => fileRef.current?.click()}
                onDragOver={e => e.preventDefault()}
                onDrop={e => { e.preventDefault(); onFile(e.dataTransfer.files[0]); }}
                style={{
                  border:"2px dashed var(--border2)", borderRadius:10, padding:"48px 24px",
                  textAlign:"center", cursor:"pointer", transition:"border-color 0.2s",
                }}
                onMouseEnter={e => e.currentTarget.style.borderColor="var(--accent)"}
                onMouseLeave={e => e.currentTarget.style.borderColor="var(--border2)"}
              >
                <div style={{ fontSize:36, marginBottom:12 }}>🎬</div>
                <div style={{ fontSize:14, fontWeight:600, marginBottom:6 }}>Drop video or image here</div>
                <div style={{ fontSize:13, color:"var(--muted2)" }}>MP4, MOV, AVI, WebM, JPG, PNG · up to 5 GB</div>
                <input ref={fileRef} type="file" accept="video/*,image/*" style={{ display:"none" }} onChange={e => onFile(e.target.files[0])} />
              </div>
            ) : (
              <div style={{ display:"flex", gap:14, alignItems:"center" }}>
                {preview && file?.type?.startsWith("image") ? (
                  <img src={preview} alt="" style={{ width:80, height:80, objectFit:"cover", borderRadius:8 }} />
                ) : (
                  <div style={{ width:80, height:80, background:"var(--bg3)", borderRadius:8, display:"flex", alignItems:"center", justifyContent:"center", fontSize:28 }}>🎬</div>
                )}
                <div style={{ flex:1 }}>
                  <div style={{ fontSize:13, fontWeight:600 }}>{file.name}</div>
                  <div style={{ fontSize:12, color:"var(--muted)", marginTop:2 }}>{(file.size / 1024 / 1024).toFixed(1)} MB</div>
                  {uploading && (
                    <div style={{ marginTop:8 }}>
                      <div style={{ height:4, background:"var(--bg3)", borderRadius:2, overflow:"hidden" }}>
                        <div style={{ height:"100%", width:`${uploadProgress}%`, background:"var(--accent)", transition:"width 0.3s" }} />
                      </div>
                      <div style={{ fontSize:11, color:"var(--muted)", marginTop:4 }}>Uploading… {uploadProgress}%</div>
                    </div>
                  )}
                  {!uploading && !mediaFile && (
                    <button className="btn btn-primary btn-sm" style={{ marginTop:8 }} onClick={uploadFile}>Upload to Server</button>
                  )}
                </div>
                <button className="btn btn-ghost btn-sm" onClick={() => { setFile(null); setPreview(null); setMediaFile(null); URL.revokeObjectURL(preview); }}>✕</button>
              </div>
            )}
          </div>

          {/* STEP 2: Content Details */}
          <div className="card">
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
              <span style={{ fontSize:14, fontWeight:700 }}>✏️ Content Details</span>
              <button className="btn btn-ghost btn-sm" onClick={generateAi} disabled={aiLoading}>
                {aiLoading ? <span className="spinner" /> : "✦ AI Generate"}
              </button>
            </div>
            <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
              <div className="field">
                <label className="label">Title <span style={{ color:"var(--red)" }}>*</span></label>
                <input className="input" placeholder="YouTube title / post headline (max 100 chars)" value={form.title} onChange={set("title")} maxLength={100} />
                <div style={{ fontSize:11, color:"var(--muted)", textAlign:"right" }}>{form.title.length}/100</div>
              </div>
              <div className="field">
                <label className="label">Caption <span style={{ color:"var(--muted)" }}>(Instagram / Social)</span></label>
                <textarea className="textarea" placeholder="Write your caption…" value={form.caption} onChange={set("caption")} maxLength={2200} rows={3} />
                <div style={{ fontSize:11, color:"var(--muted)", textAlign:"right" }}>{form.caption.length}/2200</div>
              </div>
              <div className="field">
                <label className="label">YouTube Description <span style={{ color:"var(--muted)" }}>(optional)</span></label>
                <textarea className="textarea" placeholder="Long-form description for YouTube…" value={form.description} onChange={set("description")} maxLength={5000} rows={3} />
              </div>
              <div className="field">
                <label className="label">Hashtags <span style={{ color:"var(--muted)" }}>(comma separated)</span></label>
                <input className="input" placeholder="productivity, motivation, youtube" value={form.hashtags} onChange={set("hashtags")} />
              </div>
            </div>
          </div>
        </div>

        {/* RIGHT: Platforms + Schedule */}
        <div style={{ display:"flex", flexDirection:"column", gap:16, position:"sticky", top:24 }}>
          {/* Platforms */}
          <div className="card">
            <div style={{ fontSize:14, fontWeight:700, marginBottom:12 }}>⚡ Publish To</div>
            <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
              {PLATFORMS.map(p => {
                const meta = PLATFORM_META[p];
                const connected = connectedPlatforms.includes(p);
                const selected = form.platforms.includes(p);
                return (
                  <button
                    key={p}
                    onClick={() => connected && togglePlatform(p)}
                    title={!connected ? "Connect this platform first" : ""}
                    style={{
                      display:"flex", alignItems:"center", gap:10,
                      padding:"9px 12px", borderRadius:8,
                      border:`1px solid ${selected ? meta.color + "50" : "var(--border)"}`,
                      background: selected ? `${meta.color}12` : "var(--bg3)",
                      cursor: connected ? "pointer" : "not-allowed", opacity: connected ? 1 : 0.4,
                      transition:"all 0.15s", textAlign:"left",
                    }}
                  >
                    <span style={{ color:meta.color, fontWeight:700, fontSize:12, width:16, textAlign:"center" }}>{meta.icon}</span>
                    <span style={{ fontSize:13, fontWeight:500, flex:1 }}>{p.charAt(0) + p.slice(1).toLowerCase()}</span>
                    {!connected && <span style={{ fontSize:10, color:"var(--muted)" }}>Not connected</span>}
                    {connected && selected && <span style={{ color:meta.color, fontSize:13 }}>✓</span>}
                  </button>
                );
              })}
            </div>
            {connectedPlatforms.length === 0 && (
              <div style={{ fontSize:12, color:"var(--yellow)", marginTop:10, padding:"8px 10px", background:"rgba(251,191,36,0.08)", borderRadius:6 }}>
                ⚠ Connect platforms first in <a href="/platforms" style={{ color:"var(--yellow)", textDecoration:"underline" }}>Settings</a>
              </div>
            )}
          </div>

          {/* Schedule Time */}
          <div className="card">
            <div style={{ fontSize:14, fontWeight:700, marginBottom:12 }}>📅 Schedule</div>
            <div style={{ display:"flex", flexDirection:"column", gap:12 }}>
              <div className="field">
                <label className="label">Date & Time</label>
                <input className="input" type="datetime-local" value={form.scheduledAt} onChange={set("scheduledAt")}
                  min={new Date(Date.now() + 60000).toISOString().slice(0,16)} />
              </div>
              <div className="field">
                <label className="label">Privacy</label>
                <select className="select input" value={form.privacyStatus} onChange={set("privacyStatus")}>
                  <option value="PUBLIC">🌍 Public</option>
                  <option value="UNLISTED">🔗 Unlisted</option>
                  <option value="PRIVATE">🔒 Private</option>
                </select>
              </div>
            </div>
          </div>

          {/* Submit */}
          <button
            className="btn btn-primary"
            onClick={submit}
            disabled={submitting || uploading || form.platforms.length === 0}
            style={{ padding:"13px", fontSize:15 }}
          >
            {submitting ? <span className="spinner" /> : "✓ Schedule Post"}
          </button>

          {form.platforms.length > 0 && form.scheduledAt && (
            <div style={{ fontSize:12, color:"var(--muted2)", textAlign:"center", lineHeight:1.5 }}>
              Will publish to {form.platforms.join(", ")} on{" "}
              {new Date(form.scheduledAt).toLocaleString(undefined, { weekday:"short", month:"short", day:"numeric", hour:"2-digit", minute:"2-digit" })}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

