    if (!confirm("Cancel this post?")) return;
    try { await scheduleApi.cancel(id); toast.success("Cancelled"); load(); }
    catch { toast.error("Failed to cancel"); }
  };

  const FILTERS = ["ALL","SCHEDULED","PUBLISHED","FAILED","DRAFT","CANCELLED"];

