      connection: getRedis(),
      defaultJobOptions: {
        attempts: 3,
        backoff: { type: "exponential", delay: 5000 },
        removeOnComplete: { count: 200 },
        removeOnFail: { count: 500 },
      },
    });
  }
  return queues[name];
}

async function schedulePublishJob(postId, runAt) {
  const queue = getQueue(QUEUE_NAMES.PUBLISH);
